import React, { useEffect } from "react";
import { Link } from "react-router-dom";
import "../styles/styles.css";

const Financiero = () => {

  useEffect(() => {
    // Año dinámico
    const year = document.getElementById("year");
    if (year) {
      year.textContent = new Date().getFullYear();
    }

    // Bloquear botón atrás
    window.history.pushState(null, "", window.location.href);

    window.onpopstate = function () {
      window.history.go(1);
    };

    // Bloquear ALT + flechas
    const handleKeyDown = (e) => {
      if (
        (e.altKey && e.key === "ArrowLeft") ||
        (e.altKey && e.key === "ArrowRight")
      ) {
        e.preventDefault();
      }
    };

    document.addEventListener("keydown", handleKeyDown);

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
    };
  }, []);

  return (
    <>
      <header className="site-header">
        <div className="container header-inner">

          <div className="brand">
            <span className="brand-text">Financiero</span>
          </div>

          <nav className="main-nav">
            <Link to="/cuenta">Cuenta</Link>
            <Link to="/certificado">Certificado</Link>
            <Link to="/brebe">Bre-be</Link>
            <Link to="/">Inicio</Link>
            <Link to="/registro" className="btn-register">Registro</Link>
          </nav>

        </div>
      </header>

      <main>
        <section className="hero">
          <div className="container hero-inner">

            <div className="hero-copy">
              <h1>Compromiso Financiero</h1>

              <p className="lead">
                Somos una compañía financiera nueva que está transformando lo ya existente
                en algo diferente. Comprender los problemas actuales de los usuarios
                y empresas es crucial para construir un servicio más robusto y confiable.
              </p>

              <Link to="/registro" className="cta">Registrarse</Link>
            </div>

            <div className="hero-media">
              <img
                src="/logo.jpeg"
                alt="Logo financiero"
                className="hero-logo"
              />
            </div>

          </div>
        </section>

        <section className="guarantees">
          <div className="container">

            <h2 className="section-title">
              Las Garantías De Nuestro Compromiso Financiero
            </h2>

            <div className="cards-grid">

              <div className="card">
                <div className="icono-doc">💲</div>
                <h3>Seguridad del dinero</h3>
                <p>El dinero quedará asegurado en todo momento.</p>
              </div>

              <div className="card">
                <div className="icono-doc">🔒</div>
                <h3>Seguridad al iniciar sesión</h3>
                <p>Garantía total de seguridad al acceder a tu cuenta.</p>
              </div>

              <div className="card">
                <div className="icono-doc">🔁</div>
                <h3>Transferencias</h3>
                <p>Transferencias seguras entre bancos rápidas y confiables.</p>
              </div>

              <div className="card">
                <div className="icono-doc">⟳</div>
                <h3>Actualización de movimientos</h3>
                <p>Historial actualizado en tiempo real.</p>
              </div>

              <div className="card">
                <div className="icono-doc">🚫</div>
                <h3>Bloqueo rápido</h3>
                <p>Bloqueo eficiente en caso de robo o actividades sospechosas.</p>
              </div>

              <div className="card">
                <div className="icono-doc">📄</div>
                <h3>Certificado bancario</h3>
                <p>Documento oficial que confirma la existencia de tu cuenta.</p>
              </div>

            </div>

          </div>
        </section>
      </main>

      <footer className="site-footer">
        <div className="container">
          <p>© <span id="year"></span> Financiero — Todos los derechos reservados</p>
        </div>
      </footer>
    </>
  );
};

export default Financiero;
